    if (initialData) {
      setFormData({ ...initialData });
      setId(initialData.id);
    } else {
      setFormData(emptyTransaction);
      setId('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({ ...formData, id });
    onClose();
  };

