import React, { useState, useMemo } from 'react';
import { 
  Edit2, 
  Trash2, 
  Search, 
  Filter, 
  CheckSquare, 
  Square,
  ArrowUpCircle,
  ArrowDownCircle,
  AlertCircle
} from 'lucide-react';
import { Transaction, Bank, Category, CostCenter, Participant } from '../types';

interface TransactionListProps {
  transactions: Transaction[];
  registries: {
    banks: Bank[];
    categories: Category[];
    costCenters: CostCenter[];
    participants: Participant[];
  };
  onEdit: (t: Transaction) => void;
  onDelete: (ids: string[]) => void;
}

export const TransactionList: React.FC<TransactionListProps> = ({ 
  transactions, 
  registries, 
  onEdit, 
  onDelete 
}) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: keyof Transaction, direction: 'asc' | 'desc' } | null>(null);

  // Helper to resolve ID to Name
  const getName = (list: { id: string, name: string }[], id: string) => {
    return list.find(item => item.id === id)?.name || '-';
  };

  const handleSelectAll = () => {
    if (selectedIds.length === transactions.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(transactions.map(t => t.id));
    }
  };

  const toggleSelect = (id: string) => {
    if (selectedIds.includes(id)) {
      setSelectedIds(selectedIds.filter(sid => sid !== id));
    } else {
      setSelectedIds([...selectedIds, id]);
    }
  };

  const handleBulkDelete = () => {
    if (confirm(`Tem certeza que deseja excluir ${selectedIds.length} itens?`)) {
      onDelete(selectedIds);
      setSelectedIds([]);
    }
  };

  const filteredTransactions = useMemo(() => {
    let data = [...transactions];

    if (searchTerm) {
      const lowerTerm = searchTerm.toLowerCase();
      data = data.filter(t => 
        t.description.toLowerCase().includes(lowerTerm) ||
        t.docNumber.toLowerCase().includes(lowerTerm) ||
        getName(registries.participants, t.participantId).toLowerCase().includes(lowerTerm)
      );
    }

    if (sortConfig) {
      data.sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) return sortConfig.direction === 'asc' ? -1 : 1;
        if (a[sortConfig.key] > b[sortConfig.key]) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    } else {
        // Default sort by date desc
        data.sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    }

    return data;
  }, [transactions, searchTerm, sortConfig, registries]);

  const requestSort = (key: keyof Transaction) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full">
      {/* Toolbar */}
      <div className="p-4 border-b border-slate-200 flex flex-col sm:flex-row gap-4 justify-between items-center bg-gray-50">
        <div className="flex items-center gap-2 w-full sm:w-auto">
          <div className="relative w-full sm:w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input 
              type="text" 
              placeholder="Buscar por descrição, doc..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-9 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <button className="p-2 text-gray-500 hover:bg-gray-200 rounded-lg transition-colors">
            <Filter className="w-4 h-4" />
          </button>
        </div>

        {selectedIds.length > 0 && (
          <div className="flex items-center gap-3 animate-fade-in">
            <span className="text-sm text-slate-600 font-medium">{selectedIds.length} selecionados</span>
            <button 
              onClick={handleBulkDelete}
              className="flex items-center gap-2 px-3 py-1.5 bg-red-50 text-red-600 rounded-lg text-sm hover:bg-red-100 font-medium transition-colors"
            >
              <Trash2 className="w-4 h-4" />
              Excluir Selecionados
            </button>
          </div>
        )}
      </div>

      {/* Table */}
      <div className="overflow-x-auto flex-1">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider border-b border-slate-200">
              <th className="p-4 w-12 text-center">
                <button onClick={handleSelectAll} className="text-gray-400 hover:text-blue-600">
                  {selectedIds.length === transactions.length && transactions.length > 0 ? (
