        ...prev,
        [type]: prev[type].map(item => item.id === id ? updated : item)
      }));
    },
    onDelete: async (id: string) => {
      // @ts-ignore
      await financeService.deleteRegistryItem(type, id);
      setRegistries(prev => ({
        ...prev,
        [type]: prev[type].filter(item => item.id !== id)
      }));
    }
  });

