          <h1 className="text-xl font-bold text-slate-800 capitalize">
            {activeTab === 'dashboard' && 'Painel de Controle'}
            {activeTab === 'transactions' && 'Movimentações Bancárias'}
            {activeTab === 'registries' && 'Cadastros Auxiliares'}
          </h1>

          {activeTab !== 'registries' && (
             <button 
              onClick={openNewTransaction}
              className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors shadow-sm shadow-blue-200"
            >
              <Plus className="w-4 h-4" />
              Nova Movimentação
            </button>
          )}
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-auto p-8">

          {/* Dashboard View */}
          {activeTab === 'dashboard' && (
            <div className="max-w-7xl mx-auto animate-fade-in">
              <Summary transactions={transactions} />

              <div className="mt-8">
                <h3 className="text-lg font-bold text-slate-800 mb-4">Últimas Movimentações</h3>
                <div className="h-[400px]">
                    <TransactionList 
                        transactions={transactions.slice(0, 10)} 
                        registries={registries} 
