  WALLETS: 'fincontrol_wallets',
};

// Helper to simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Generic CRUD helper
function getEntity<T>(key: string, initial: T[]): T[] {
  const stored = localStorage.getItem(key);
  if (!stored) return initial;
  return JSON.parse(stored);
}

function saveEntity<T>(key: string, data: T[]) {
  localStorage.setItem(key, JSON.stringify(data));
}

// Service Implementation
export const financeService = {
  // --- Transactions ---
  async getTransactions(): Promise<Transaction[]> {
    await delay(300);
    return getEntity<Transaction>(KEYS.TRANSACTIONS, INITIAL_DATA.transactions);
  },

  async saveTransaction(transaction: Transaction): Promise<Transaction> {
    await delay(300);
    const list = getEntity<Transaction>(KEYS.TRANSACTIONS, INITIAL_DATA.transactions);
    const index = list.findIndex(t => t.id === transaction.id);

    if (index >= 0) {
      list[index] = transaction;
    } else {
      list.push({ ...transaction, id: Math.random().toString(36).substr(2, 9) });
    }

    saveEntity(KEYS.TRANSACTIONS, list);
    return transaction;
  },

  async deleteTransactions(ids: string[]): Promise<void> {
    await delay(300);
    let list = getEntity<Transaction>(KEYS.TRANSACTIONS, INITIAL_DATA.transactions);
    list = list.filter(t => !ids.includes(t.id));
    saveEntity(KEYS.TRANSACTIONS, list);
  },

  // --- Registries (Generic) ---
  async getRegistry<T>(type: 'banks' | 'categories' | 'costCenters' | 'participants' | 'wallets'): Promise<T[]> {
    await delay(200);
    switch (type) {
      case 'banks': return getEntity(KEYS.BANKS, INITIAL_DATA.banks) as unknown as T[];
      case 'categories': return getEntity(KEYS.CATEGORIES, INITIAL_DATA.categories) as unknown as T[];
      case 'costCenters': return getEntity(KEYS.COST_CENTERS, INITIAL_DATA.costCenters) as unknown as T[];
      case 'participants': return getEntity(KEYS.PARTICIPANTS, INITIAL_DATA.participants) as unknown as T[];
      case 'wallets': return getEntity(KEYS.WALLETS, INITIAL_DATA.wallets) as unknown as T[];
    }
    return [];
  },

  async saveRegistryItem<T extends { id: string, name: string }>(type: 'banks' | 'categories' | 'costCenters' | 'participants' | 'wallets', item: T): Promise<T> {
    await delay(200);
    const keyMap = {
      banks: KEYS.BANKS,
      categories: KEYS.CATEGORIES,
      costCenters: KEYS.COST_CENTERS,
      participants: KEYS.PARTICIPANTS,
      wallets: KEYS.WALLETS
    };

    const initialMap = {
        banks: INITIAL_DATA.banks,
        categories: INITIAL_DATA.categories,
        costCenters: INITIAL_DATA.costCenters,
        participants: INITIAL_DATA.participants,
        wallets: INITIAL_DATA.wallets
    };

    const list = getEntity<T>(keyMap[type], initialMap[type] as unknown as T[]);
    const index = list.findIndex(x => x.id === item.id);

    if (index >= 0) {
      list[index] = item;
    } else {
      list.push({ ...item, id: Math.random().toString(36).substr(2, 9) });
    }

    saveEntity(keyMap[type], list);
    return item;
  },

  async deleteRegistryItem(type: 'banks' | 'categories' | 'costCenters' | 'participants' | 'wallets', id: string): Promise<void> {
     const keyMap = {
      banks: KEYS.BANKS,
      categories: KEYS.CATEGORIES,
      costCenters: KEYS.COST_CENTERS,
      participants: KEYS.PARTICIPANTS,
      wallets: KEYS.WALLETS
    };
    const initialMap = {
        banks: INITIAL_DATA.banks,
        categories: INITIAL_DATA.categories,
        costCenters: INITIAL_DATA.costCenters,
        participants: INITIAL_DATA.participants,
        wallets: INITIAL_DATA.wallets
    };

    let list = getEntity<BaseEntity>(keyMap[type], initialMap[type] as BaseEntity[]);
    list = list.filter(x => x.id !== id);
    saveEntity(keyMap[type], list);
  }
};
